const EXAM_PAPERS = {"2023": {"title": "2023年护理责任组长竞聘考试真题", "questionCount": 85, "questions": [{"num": 1, "type": "judge", "question": "非同步直流电除颤后应立即查看患者自主心率是否恢复", "options": {"A": "正确", "B": "错误"}, "answer": "B", "analysis": "非同步直流电除颤后，不应立即查看自主心率是否恢复，而应立即继续进行胸外心脏按压。根据AHA心肺复苏指南，除颤后应立即恢复胸外按压，不应因检查心律而中断按压。", "keyPoint": "电除颤后的操作流程", "memoryTip": "除颤后继续按压，不中断"}, {"num": 2, "type": "judge", "question": "火灾应急处理病区疏散支援原则是上二下一不动其余各楼层支援一名（即发生火灾楼层的上面两层及下面一层不动随时准备疏散，其余各楼层安排一名工作人员到达火灾现场支援）", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "病区火灾疏散支援原则为'上二下一不动'：起火楼层的上面两层及下面一层不动随时准备疏散，其余各楼层各安排一名工作人员到火灾现场支援。", "keyPoint": "火灾应急疏散原则", "memoryTip": "上二下一不动，其余各出一人"}, {"num": 3, "type": "judge", "question": "每日咯血量在500ml以上或一次咯血量大于300ml为大量咯血", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "大量咯血标准：每日咯血量>500ml，或一次咯血量>300ml。少量咯血<100ml/d；中量咯血100~500ml/d。大量咯血是急症，可因血块堵塞气道导致窒息死亡。", "keyPoint": "咯血量的分级标准", "memoryTip": "大量咯血=日>500ml或一次>300ml"}, {"num": 4, "type": "judge", "question": "心源性水肿主要是右心衰的表现，为对称性、非凹陷性水肿，颜面部一般不肿", "options": {"A": "正确", "B": "错误"}, "answer": "B", "analysis": "心源性水肿主要是右心衰的表现，为对称性、凹陷性水肿，从身体低垂部位开始。题目中非凹陷性描述有误。肾源性水肿从眼睑面部开始，为非凹陷性。", "keyPoint": "心源性水肿的特点", "memoryTip": "心源性=凹陷+下垂部；肾源性=眼睑"}, {"num": 5, "type": "judge", "question": "雷诺现象的皮肤颜色变化顺序为白→紫→红", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "雷诺现象是由于肢端小动脉阵发性痉挛导致的皮肤颜色变化，典型顺序为：苍白(缺血期)到发绀(缺氧期)到潮红(充血恢复期)。", "keyPoint": "雷诺现象的临床表现", "memoryTip": "白到紫到红"}, {"num": 6, "type": "judge", "question": "深部组织损伤期：缺损涉及到组织全层，但溃疡完全被创面的腐肉和焦痂所覆盖", "options": {"A": "正确", "B": "错误"}, "answer": "B", "analysis": "题目描述是'不可分期'压疮，非深部组织损伤期。深部组织损伤期皮肤完整、呈紫色或褐红色瘀斑。缺损涉及全层且被腐肉和焦痂覆盖是不可分期的特征。", "keyPoint": "压疮的分期判断", "memoryTip": "深部损伤=皮肤完整+瘀斑；腐肉焦痂=不可分期"}, {"num": 7, "type": "judge", "question": "克罗恩病主要累及回肠末段", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "克罗恩病最常累及回肠末段及邻近右半结肠，可累及全消化道呈跳跃性分布。溃疡性结肠炎主要累及直肠乙状结肠呈连续性分布。", "keyPoint": "克罗恩病的好发部位", "memoryTip": "克罗恩=回肠末段(跳跃性)；溃结=直肠乙状结肠(连续性)"}, {"num": 8, "type": "judge", "question": "洋地黄中毒最严重的不良反应是心律失常", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "洋地黄中毒时心脏毒性是最严重的不良反应，表现为各种心律失常(室早二联律最常见，严重可致室速室颤)，可直接危及生命。", "keyPoint": "洋地黄中毒的不良反应", "memoryTip": "洋地黄最严重=心律失常(心脏毒性)"}, {"num": 9, "type": "judge", "question": "疼痛是由实际或在的组织损伤，所引起的一种不愉快的感觉和主观体验。已被列为第五大生命体征", "options": {"A": "正确", "B": "错误"}, "answer": "A", "analysis": "疼痛已被WHO列为第五大生命体征(继体温脉搏呼吸血压之后)。定义为与实际或潜在组织损伤相关的不愉快感觉和情感体验。", "keyPoint": "疼痛的医学定义与地位", "memoryTip": "疼痛=第五大生命体征"}, {"num": 10, "type": "judge", "question": "低盐饮食中钠含量应低于1.5g/d", "options": {"A": "正确", "B": "错误"}, "answer": "B", "analysis": "低盐饮食要求每日烹调用食盐不超过2g(含钠量<0.8g/d)，而非1.5g/d。WHO推荐成人每日食盐<5g/d。", "keyPoint": "低盐饮食的量化标准", "memoryTip": "低盐饮食=食盐<2g/d"}, {"num": 11, "type": "single", "question": "引起支气管肺炎最常见的细菌是", "options": {"A": "大肠埃希菌", "B": "变形杆菌", "C": "脑膜炎双球菌", "D": "金黄色葡萄球菌", "E": "肺炎链球菌"}, "answer": "E", "analysis": "支气管肺炎最常见致病菌是肺炎链球菌(肺炎球菌)。金黄色葡萄球菌也可引起但较少见；大肠埃希菌和变形杆菌多见于院内感染；脑膜炎双球菌主要引起流脑。", "keyPoint": "支气管肺炎的病原学", "memoryTip": "支气管肺炎最常见菌=肺炎链球菌"}, {"num": 12, "type": "single", "question": "血管壁功能异常所致的出血性疾病为", "options": {"A": "特发性血小板减少性紫癜", "B": "血友病", "C": "弥散性紫癜", "D": "过敏性紫癜"}, "answer": "D", "analysis": "过敏性紫癜属血管壁功能异常所致(过敏性血管炎致毛细血管脆性增加)。ITP属血小板异常；血友病属凝血因子缺乏。", "keyPoint": "出血性疾病的病因分类", "memoryTip": "过敏性紫癜=血管壁异常"}, {"num": 13, "type": "single", "question": "叶某，女，56岁。有\"风湿性心脏病\"病史。自诉心慌。心电图:P波消失，代之以间距、振幅不等的颤动波，QRS波正常，心室率120次/分，R-R间距绝对不等。该病人的心电图诊断为", "options": {"A": "室上性心动过速", "B": "室性心动过速", "C": "房性心动过速", "D": "心房扑动", "E": "心房颤动"}, "answer": "E", "analysis": "房颤ECG特征：P波消失代以f波(颤动波)，QRS波形态正常，R-R间距绝对不等。该患者心电图完全符合房颤诊断。风心病是房颤的常见病因。", "keyPoint": "心房颤动的心电图特征", "memoryTip": "P消失+f波+R-R绝对不等=房颤"}, {"num": 14, "type": "single", "question": "患者女性，30岁。近日无明显诱因出现咳嗽、乏力、四肢关节酸痛，伴左侧小腿散在出血点，牙龈红肿出血。血常规示：Hb 34g/L，WBC 4.3×10/L，PLT 16×10/L。骨髓穿刺示：骨髓增生活跃，原始白细胞33.5%。根据上述临床表现和检查结果，患者目前最可能的诊断是", "options": {"A": "溶血性贫血", "B": "再生障碍性贫血", "C": "急性白血病", "D": "特发性血小板减少性紫癜", "E": "血友病"}, "answer": "C", "analysis": "骨髓穿刺示原始白细胞33.5%(>=20%即可诊为急性白血病)。患者有出血倾向、重度贫血、血小板降低。再障骨髓增生低下且无原始细胞增高。", "keyPoint": "急性白血病的诊断依据", "memoryTip": "骨髓原始细胞>=20%=急性白血病"}, {"num": 15, "type": "single", "question": "血糖仪质控时机错误的是", "options": {"A": "每天血糖检测前", "B": "更换新批号试纸条", "C": "每次血糖检测前", "D": "血糖仪更换电池", "E": "器及试纸条可能未处于最佳状态时"}, "answer": "C", "analysis": "血糖仪质控不需要每次检测前都做。质控时机包括：每天血糖检测前、更换新批号试纸条时、更换电池后、仪器或试纸可能未处于最佳状态时。", "keyPoint": "血糖仪的质控要求", "memoryTip": "质控不等同每次测前，而是每天+更换耗材时"}, {"num": 16, "type": "single", "question": "输血引起溶血反应，最早出现的主要表现为", "options": {"A": "少尿", "B": "寒战、高热", "C": "呼吸困难、血压下降", "D": "瘙痒、皮疹", "E": "头部胀痛、面部潮红、恶心、呕吐、腰背部剧痛"}, "answer": "E", "analysis": "输血溶血反应最早典型表现为头部胀痛、面部潮红、腰背部剧痛、恶心呕吐。因不相容红细胞破坏释放血红蛋白刺激所致。寒战高热稍后出现。", "keyPoint": "输血溶血反应的最早表现", "memoryTip": "溶血最早=腰背剧痛+头部胀痛+面部潮红"}, {"num": 17, "type": "single", "question": "关于颅神经说法错误的是（）", "options": {"A": "嗅神经，主要负责鼻子的嗅觉", "B": "外展神经，主管眼球向外下方的运动", "C": "视神经，主管眼睛的视物功能", "D": "滑车神经，主管眼球向外下方的运动"}, "answer": "B", "analysis": "外展神经(第六对)主管眼球向外运动，非向外下方。向外下方运动由滑车神经(第四对)支配。选项B混淆了两者功能。", "keyPoint": "颅神经功能", "memoryTip": "外展=向外；滑车=向外下"}, {"num": 18, "type": "single", "question": "急性前壁心肌梗死的特征性心电图改变见于（）（1分）", "options": {"A": "V1-V6导联", "B": "V1-V3导联", "C": "V3-V5导联", "D": "I、aVL导联", "E": "V1-V3及I、aVL导联"}, "answer": "C", "analysis": "成人正常脉压差(收缩压减舒张压)=30~40mmHg。脉压差>60见于主动脉瓣关闭不全；<20见于心包积液休克。", "keyPoint": "正常脉压差范围", "memoryTip": "正常脉压差=30~40mmHg"}, {"num": 19, "type": "single", "question": "人体铁剂吸收的主要部位是（）（1分）", "options": {"A": "胃体部", "B": "胃窦部", "C": "十二指肠及空肠上部", "D": "十二指肠球部", "E": "空肠与回肠"}, "answer": "C", "analysis": "疼痛评估核心原则：疼痛是主观感受(A对)；评估以患者主诉为金标准(B对)；需结合其他指标综合判断(D对)。不能相信患者主诉是错误观念。", "keyPoint": "疼痛评估原则", "memoryTip": "信患者+看指标=综合判断"}, {"num": 20, "type": "single", "question": "抢救糖尿病酮症酸中毒病人最首要和关键的措施是（）（1分）", "options": {"A": "治疗诱因", "B": "使用小剂量胰岛素", "C": "补液", "D": "纠正电解质紊乱及酸碱平衡失调", "E": "纠正脑水肿"}, "answer": "C", "analysis": "客观资料=可观察/测量(面色A、血压130/80 B)。主观资料=患者自身感受(头晕C、发麻D、恶心E)。", "keyPoint": "客观与主观资料的区分", "memoryTip": "客观=能看能测；主观=患者自述感受"}, {"num": 21, "type": "single", "question": "保护具不适用于（1分）", "options": {"A": "躁动不安者", "B": "高热者", "C": "谵妄者", "D": "昏迷者", "E": "不愿配合治疗者"}, "answer": "E", "analysis": "题目问哪项不属于心源性水肿。心源性水肿从身体下垂部位开始(A是)；从眼睑面部开始(B)是肾源性水肿特征，不属于心源性。活动后加重(C)和休息后减轻(D)均为心源性特点。", "keyPoint": "心源性水肿与肾源性水肿的鉴别", "memoryTip": "心源性=下垂部开始；肾源性=眼睑面部开始"}, {"num": 22, "type": "single", "question": "细胞内液最主要的阳离子为（1分）", "options": {"A": "K+", "B": "Ca2+", "C": "NA+", "D": "Fe2+", "E": "Mg2+"}, "answer": "A", "analysis": "PaO2 50mmHg+PaCO2 68mmHg+pH 7.30=II型呼衰。首要护理问题是气体交换受损，因肺泡-毛细血管膜气体交换障碍导致缺氧和CO2潴留。", "keyPoint": "COPD合并呼衰的护理问题", "memoryTip": "COPD+呼衰首要=气体交换受损"}, {"num": 23, "type": "single", "question": "患者女性，25岁。因患系统性红斑狼疮住院2次，本次住院面部红斑明显，伴有乏力、食欲减退等。造成该患者皮肤红斑的主要原因是（1分）", "options": {"A": "日晒过多", "B": "皮肤过敏", "C": "长期使用免疫抑制剂", "D": "青春期痤疮", "E": "免疫复合物沉积"}, "answer": "E", "analysis": "题目问哪项不是急性左心衰表现。左心衰=肺淤血(呼吸困难、泡沫痰)。颈静脉怒张(D)是右心衰(体循环淤血)的体征，不是左心衰表现。", "keyPoint": "急性左心衰与右心衰鉴别", "memoryTip": "左心衰=肺淤血；右心衰=颈静脉怒张+肝大+水肿"}, {"num": 24, "type": "single", "question": "阿司匹林治疗脑动脉硬化的原理是（1分）", "options": {"A": "降低血黏度", "B": "增加血管壁弹性", "C": "扩张小动脉", "D": "降低毛细血管通透性"}, "answer": "A", "analysis": "走纸25mm/s时横向每小格=0.04s(非0.02s)。选项C每小格代表0.02s是错误的。纵向每小格=0.1mV。A、B、D、E均为正确描述。", "keyPoint": "心电图记录纸的标尺含义", "memoryTip": "横小格=0.04s，纵小格=0.1mV"}, {"num": 25, "type": "single", "question": "肝豆状核变性是由于下列哪种元素在体内的沉积引起的（1分）", "options": {"A": "铁", "B": "钙", "C": "铜", "D": "汞"}, "answer": "C", "analysis": "淋雨受凉史+高热+铁锈色痰=肺炎球菌肺炎典型表现。铁锈色痰因肺泡内红细胞破坏释放含铁血黄素所致。", "keyPoint": "肺炎球菌肺炎的典型特征", "memoryTip": "淋雨+高热+铁锈色痰=肺炎球菌肺炎"}, {"num": 26, "type": "single", "question": "缺铁性贫血病人服铁剂停药时间原则为（1分）", "options": {"A": "服至血红蛋白及红细胞接近正常", "B": "服至血红蛋白及红细胞正常", "C": "服至血红蛋白及红细胞正常后半个月", "D": "服至血红蛋白及红细胞正常后1个月", "E": "服至血红蛋白及红细胞正常后3-6个月"}, "answer": "E", "analysis": "II级=日常活动轻度受限，爬2层楼可诱发症状。I级不受限；III级低于日常活动即受限；IV级休息时也有症状。患者爬2楼胸闷气喘符合II级。", "keyPoint": "心功能NYHA分级", "memoryTip": "心功能II级=爬楼可诱发"}, {"num": 27, "type": "single", "question": "高血糖高渗性昏迷应首先采取的抢救措施为（1分）", "options": {"A": "大量补充液体", "B": "积极纠正酸中毒", "C": "小剂量胰岛素治疗", "D": "平衡电解质紊乱", "E": "使用中枢兴奋剂"}, "answer": "A", "analysis": "题目问使颅内压增高的因素不包括。脑血流量减少(B)会降低颅内压，是唯一不增高颅内压的因素。PaCO2增高、血压升高、中心静脉压增高、PaO2下降均使颅压增高。", "keyPoint": "颅内压增高的影响因素", "memoryTip": "脑血流量减少=唯一降颅压因素"}, {"num": 28, "type": "single", "question": "高血压危象紧急处理的关键是（1分）", "options": {"A": "绝对卧床休息", "B": "降低颅内压", "C": "迅速降低血压", "D": "给予氧气吸入", "E": "限制钠盐摄入"}, "answer": "B", "analysis": "浅反射=刺激皮肤黏膜(角膜/腹壁/提睾/跖/肛门反射)。深反射=刺激肌腱骨膜(肱二头肌/桡/踝反射等)。肛门反射(A)属浅反射，其余选项均属深反射。", "keyPoint": "浅反射与深反射的区分", "memoryTip": "肛门反射=浅反射；桡/踝/肱二头肌反射=深反射"}, {"num": 29, "type": "single", "question": "护理频繁呕吐伴有突然头痛的患者时，突然发现其意识不清脉搏呼吸减慢，左右瞳孔明显不等大，应考虑（1分）", "options": {"A": "蛛网膜下腔出血", "B": "脑疝形成", "C": "高血压危象", "D": "癫痫发作", "E": "脑血栓形成"}, "answer": "B", "analysis": "颅内压增高典型三联征：头痛+喷射性呕吐+视盘水肿，称为Cushing三联征。", "keyPoint": "颅内压增高的典型表现", "memoryTip": "颅内高压=头痛+喷射性呕吐+视盘水肿"}, {"num": 30, "type": "single", "question": "药液漏出血管外，可导致局部缺血坏死的药物是（1分）", "options": {"A": "麻黄碱", "B": "异丙肾上腺素", "C": "去甲肾上腺素", "D": "肾上腺素"}, "answer": "C", "analysis": "血肌酐是评价肾小球滤过率(GFR)最常用的内源性标志物，主要经肾小球滤过不被肾小管重吸收。尿渗量尿比重反映肾小管浓缩功能。", "keyPoint": "肾小球滤过功能指标", "memoryTip": "GFR=血肌酐；肾小管功能=尿渗量"}, {"num": 31, "type": "single", "question": "董某，男，20岁。因车祸入院。身体评估:呼之不应，问之不答，压眶时可见痛苦表情和肢体躲避反应。该病人的意识障碍属于", "options": {"A": "嗜睡", "B": "意识模糊", "C": "昏睡", "D": "浅昏迷", "E": "深昏迷"}, "answer": "D", "analysis": "COPD肺气肿病史30年+抬重物(诱因)+突然一侧胸痛+气急发绀=自发性气胸(肺大泡破裂)。心梗有ECG心肌酶改变；胸腔积液起病缓。", "keyPoint": "自发性气胸的临床诊断", "memoryTip": "COPD+用力后一侧胸痛气急=自发性气胸"}, {"num": 32, "type": "single", "question": "苏某，女，34岁。1周前被诊断患有慢性肾小球肾炎，查血尿素氮和血肌酐均明显高于正常。目前该病人的蛋白质摄入应为", "options": {"A": "正常量", "B": "低蛋白饮食", "C": "零蛋白饮食", "D": "1.0~1.2g/(kg·d)", "E": "0.6~0.8g/(kg·d)的优质蛋白"}, "answer": "E", "analysis": "脑出血最好发内囊(基底节区)，占50-60%。豆纹动脉从大脑中动脉呈直角分出承受压力大，在高血压情况下易破裂。", "keyPoint": "脑出血的最好发部位", "memoryTip": "脑出血最多见=内囊/基底节区"}, {"num": 33, "type": "single", "question": "大量蛋白尿是指尿蛋白定量大于", "options": {"A": "1.5g/d", "B": "3.5g/d", "C": "4.0g/d", "D": "5.0g/d"}, "answer": "B", "analysis": "纠正缺氧和CO2潴留最重要的措施是保持呼吸道通畅(B)，这是所有呼吸支持治疗的前提和基础。氧疗需以气道通畅为前提。", "keyPoint": "呼吸衰竭的首要处理措施", "memoryTip": "呼衰首要=保持呼吸道通畅(气道优先)"}, {"num": 34, "type": "multi", "question": "下列有关心电图记录纸描述错误的是（1分）", "options": {"A": "横线代表时间", "B": "纵线代表电压", "C": "走纸速度25mm/s时，每小格(横向)代表0.02s", "D": "走纸速度25mm/s时，每小格(横向)代表0.04s", "E": "标准电压10mm/Mv时，每小格(纵向)代表0.1Mv"}, "answer": "C", "analysis": "走纸25mm/s时横向每小格=0.04s(非0.02s)。选项C错误。同第24题。", "keyPoint": "心电图记录纸标尺(重复)", "memoryTip": "横小格=0.04s"}, {"num": 35, "type": "multi", "question": "李某，女，26岁。淋暴雨后突然出现高热，体温最高达39.8℃，伴咳嗽、咳痰，痰液为铁锈色。该病人最可能的诊断是（）", "options": {"A": "肺炎球菌肺炎", "B": "阿米巴肺脓肿", "C": "急性肺水肿", "D": "克雷伯杆菌肺炎", "E": "普通感冒"}, "answer": "A", "analysis": "淋雨+高热+铁锈色痰=肺炎球菌肺炎。同第25题。", "keyPoint": "肺炎球菌肺炎(重复)", "memoryTip": "淋雨+铁锈色痰=肺炎球菌肺炎"}, {"num": 36, "type": "single", "question": "某心脏病患者，在日常活动中爬2层楼楼梯即会感觉胸闷气喘，需休息一会才能缓解", "options": {"A": "I级", "B": "II级", "C": "III级", "D": "IV级"}, "answer": "B", "analysis": "II级=日常活动轻度受限，爬楼可诱发症状。同第26题。", "keyPoint": "心功能NYHA分级(重复)", "memoryTip": "II级=爬楼可诱发"}, {"num": 37, "type": "multi", "question": "使颅内压增高的因素不包括", "options": {"A": "PaCO2增高", "B": "脑血流量减少", "C": "血压升高", "D": "中心静脉压增高", "E": "PaO2下降"}, "answer": "B", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 38, "type": "single", "question": "下列哪项属浅反射", "options": {"A": "肛门反射", "B": "桡反射", "C": "踝反射", "D": "肱二头肌反射"}, "answer": "A", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 39, "type": "single", "question": "颅内压增高的典型表现是", "options": {"A": "眩晕伴呕吐", "B": "头痛、呕吐、视盘水肿", "C": "躁动不安、胡言乱语", "D": "短暂意识丧失、脉搏加速"}, "answer": "B", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 40, "type": "multi", "question": "常用于反映肾小球滤过功能的指标是()", "options": {"A": "血肌酐", "B": "尿渗量", "C": "尿蛋白", "D": "昼夜尿比重", "E": "尿β微球蛋白"}, "answer": "A", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 41, "type": "multi", "question": "患者，李先生，68岁，有慢性支气管炎，肺气肿病30年，今日中午在家抬重物，突然右侧胸部刺痛，逐渐加重，伴有气急，发绀。最可能发生的是", "options": {"A": "心肌梗死", "B": "胸腔积液", "C": "自发性气胸", "D": "胸栓塞", "E": "支气管栓塞"}, "answer": "C", "analysis": "COPD+用力后一侧胸痛气急=自发性气胸。同第31题。", "keyPoint": "自发性气胸(重复)", "memoryTip": "COPD+胸痛气急=自发性气胸"}, {"num": 42, "type": "multi", "question": "脑出血最好发的部位在", "options": {"A": "脑桥", "B": "内囊", "C": "小脑", "D": "大脑皮质", "E": "中脑"}, "answer": "B", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 43, "type": "multi", "question": "纠正缺氧和二氧化碳潴留最重要的措施是", "options": {"A": "氧气疗法", "B": "保持呼吸道通畅", "C": "开放气道", "D": "纠正酸碱平衡失调", "E": "提高呼吸系统兴奋性"}, "answer": "B", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 44, "type": "single", "question": "急性肺栓塞的溶栓时间窗（1分）", "options": {"A": "14天", "B": "6h", "C": "12h", "D": "14h"}, "answer": "A", "analysis": "肺栓塞溶栓时间窗为14天，是各类血栓性疾病中最宽的。脑梗死溶栓窗4.5小时；心梗12小时。最佳为发病48小时内，但14天内仍可考虑。", "keyPoint": "急性肺栓塞的溶栓时间窗", "memoryTip": "肺栓塞溶栓窗=14天(最宽)"}, {"num": 45, "type": "multi", "question": "老年患者突然发生寒战、高热、咳嗽、咳痰、痰粘稠，砖红色，胶脓状，引起感染最可能的病原菌是（1分）", "options": {"A": "肺炎克雷白杆菌", "B": "流感嗜血杆菌", "C": "嗜肺军团杆菌", "D": "葡萄球菌", "E": "铜绿假单胞菌"}, "answer": "A", "analysis": "砖红色胶冻样痰是肺炎克雷白杆菌肺炎的特征性表现。肺炎球菌=铁锈色痰；金葡菌=脓血痰；铜绿假单胞菌=翠绿色痰。", "keyPoint": "肺炎克雷白杆菌肺炎的痰液特征", "memoryTip": "砖红胶冻痰=克雷白杆菌"}, {"num": 46, "type": "single", "question": "患者女性，20岁。诊断为特发性癫痫，病史4年，表现为全身性强直一阵挛发作，每月发作3～4次。强直，阵挛发作的特征是（1分）", "options": {"A": "发作时意识清楚", "B": "自主神经症状明显", "C": "肢体有针刺和麻木感", "D": "突然、短暂、快速的肌肉收缩", "E": "全身对称性抽搐和意识丧失"}, "answer": "E", "analysis": "大发作的特征是意识丧失+全身对称性抽搐。强直期全身骨骼肌持续收缩，阵挛期交替收缩松弛。发作时意识完全丧失，非清醒。", "keyPoint": "全身强直-阵挛发作特征", "memoryTip": "大发作=意识丧失+全身对称性抽搐"}, {"num": 47, "type": "single", "question": "董某，男，32岁，教师。慢性周期性上腹痛1年余，头晕及活动后心悸气促1周。血常规:Hb72g/L。该病人贫血的严重程度为（）", "options": {"A": "轻度", "B": "中度", "C": "重度", "D": "极重度", "E": "轻至中度"}, "answer": "B", "analysis": "Hb 72g/L=中度贫血(60~90g/L)。轻度90~120g/L；重度30~60g/L；极重度<30g/L。患者有慢性上腹痛+大便隐血阳性提示消化道出血。", "keyPoint": "贫血严重程度分级", "memoryTip": "Hb 60-90=中度贫血"}, {"num": 48, "type": "single", "question": "自然光线下，瞳孔直径小于多少毫米为缩小（1分）", "options": {"A": "4MM", "B": "3MM", "C": "2MM", "D": "1MM"}, "answer": "C", "analysis": "正常瞳孔直径2-5mm(自然光)。<2mm为瞳孔缩小(有机磷/吗啡中毒、脑桥出血)；>5mm为瞳孔散大(阿托品中毒、脑疝)。", "keyPoint": "瞳孔大小判断", "memoryTip": "瞳孔<2mm缩小，>5mm散大"}, {"num": 49, "type": "single", "question": "胃溃疡的疼痛特点是（）", "options": {"A": "疼痛-进食-疼痛", "B": "疼痛-进食-缓解", "C": "进食-疼痛-瘀痛", "D": "进食-疼痛-缓解", "E": "疼痛无规律"}, "answer": "D", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 50, "type": "single", "question": "肝性脑病灌肠时不能选用（）", "options": {"A": "清水", "B": "肥皂水", "C": "生理盐水", "D": "弱酸性溶液", "E": "新霉素液"}, "answer": "B", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 51, "type": "single", "question": "爆发痛药物解救剂量为前24H药物总量的？（1分）", "options": {"A": "5-10%", "B": "10-20%", "C": "20-30%", "D": "30-40%"}, "answer": "B", "analysis": "爆发痛(突破性疼痛)的药物解救剂量为前24小时阿片类药物总剂量的10~20%。WHO三阶梯止痛原则要求使用即释型阿片解救。", "keyPoint": "爆发痛解救剂量", "memoryTip": "爆发痛解救=前24h总量10~20%"}, {"num": 52, "type": "single", "question": "白血病的特异性体征为（）", "options": {"A": "头痛", "B": "关节痛", "C": "胸骨下段压痛", "D": "肢体瘫痪", "E": "皮肤瘀点"}, "answer": "C", "analysis": "", "keyPoint": "", "memoryTip": ""}, {"num": 53, "type": "single", "question": "女性乳腺癌的好发年龄是（1分）", "options": {"A": "20~30岁", "B": "30~40岁", "C": "40~49岁", "D": "50~55岁"}, "answer": "C", "analysis": "女性乳腺癌好发年龄为40~49岁，正值围绝经期激素水平波动大。45~55岁仍高发但略低于40~49岁。", "keyPoint": "女性乳腺癌好发年龄", "memoryTip": "乳腺癌好发40~49岁(围绝经期)"}, {"num": 54, "type": "single", "question": "原发性肝癌最早、最常见的转移方式是（）", "options": {"A": "淋巴转移", "B": "肝内血行转移", "C": "肝外血行转移", "D": "消化道转移", "E": "种植转移"}, "answer": "B", "analysis": "原发性肝癌最早最常见的转移方式=肝内血行转移(通过门静脉形成癌栓)。其次为肝外血行转移(肺最多)、淋巴转移和种植转移。", "keyPoint": "原发性肝癌的转移方式", "memoryTip": "肝癌最早转移=肝内血行(门静脉癌栓)"}, {"num": 55, "type": "single", "question": "如果病人膀胱过度膨胀，一次放尿量不超过", "options": {"A": "500ML", "B": "800ML", "C": "1000ML", "D": "1200ML"}, "answer": "C", "analysis": "膀胱过度膨胀时一次放尿不超过1000ml。原因：1)腹内压骤降可致虚脱；2)膀胱内压骤降可致黏膜血管破裂出血。应分次缓慢放尿。", "keyPoint": "膀胱过度膨胀首次放尿量", "memoryTip": "首次放尿小于等于1000ml"}, {"num": 56, "type": "single", "question": "最能反应昏迷病人病情的体征变化是", "options": {"A": "体温", "B": "脉搏", "C": "呼吸", "D": "瞳孔", "E": "神志"}, "answer": "D", "analysis": "瞳孔变化最能反映昏迷病人的病情严重程度和脑干功能状态。双侧散大固定=濒死/脑疝；针尖样=脑桥出血/吗啡中毒；一侧散大=同侧脑疝。", "keyPoint": "昏迷病人的病情观察", "memoryTip": "昏迷观察核心=瞳孔变化"}, {"num": 57, "type": "single", "question": "短暂性脑缺血发作，持续时间为", "options": {"A": "不超过24H", "B": "不超过1H", "C": "不超过一周", "D": "不超过2日"}, "answer": "A", "analysis": "TIA持续时间不超过24小时，不遗留神经功能缺损症状，影像学检查无责任病灶。超过24小时考虑脑梗死。", "keyPoint": "短暂性脑缺血发作(TIA)持续时间", "memoryTip": "TIA<=24h，无后遗症"}, {"num": 58, "type": "single", "question": "叶某，女，33岁。间歇性发热、纳差，伴腕膝关节酸痛1月余。抗Sm抗体(+)。你认为目前该病人可能患有的疾病是", "options": {"A": "风湿性关节炎", "B": "类风湿关节炎", "C": "系统性红斑狼疮", "D": "急性肾小球肾炎", "E": "病毒性肝炎"}, "answer": "C", "analysis": "年轻女性+多系统损害(关节痛/口腔溃疡/发热/蛋白尿/血液异常)+抗Sm抗体阳性=SLE。抗Sm抗体特异性高达99%，是SLE标志性抗体。", "keyPoint": "系统性红斑狼疮(SLE)的诊断", "memoryTip": "年轻女性+多系统+抗Sm阳性=SLE"}, {"num": 59, "type": "single", "question": "胡某，男，45岁。身高175cm，体重60kg。因肺部感染诱发酮症酸中毒，急诊入院。该病人应每小时泵入胰岛素", "options": {"A": "4U", "B": "5U", "C": "6U", "D": "7U", "E": "8U"}, "answer": "C", "analysis": "DKA采用持续小剂量胰岛素泵入，剂量0.1U/(kg·h)。患者60kg即6U/h。优点是血胰岛素浓度稳定、低血糖和低钾风险小。", "keyPoint": "DKA胰岛素治疗", "memoryTip": "DKA胰岛素=0.1U/kg/h，60kg=6U/h"}, {"num": 60, "type": "single", "question": "急性心肌梗死时出现的室性心律失常，首选用药是", "options": {"A": "利多卡因", "B": "洋地黄", "C": "普罗帕酮", "D": "异搏定", "E": "美托洛尔"}, "answer": "A", "analysis": "急性心梗出现的室性心律失常首选利多卡因(Ib类)。洋地黄禁用于心梗24小时内。普罗帕酮(Ic类)CAST试验证实增加心梗后死亡率。", "keyPoint": "心梗室性心律失常用药", "memoryTip": "心梗室性心律失常首选利多卡因"}, {"num": 61, "type": "single", "question": "当患者血压高于正常范围，心电监护报警上限设置范围？", "options": {"A": "5-10%", "B": "15-20%", "C": "10-15%", "D": "20-30%"}, "answer": "A", "analysis": "血压高于正常范围时报警上限一般设为高于基础值5~10%。设置过宽起不到预警作用，过窄则频繁报警影响工作。", "keyPoint": "心电监护报警上限设置", "memoryTip": "报警上限=高于基础值5~10%"}, {"num": 62, "type": "multi", "question": "急进型肾炎的病理下述哪项不正确", "options": {"A": "肾小球囊腔内新月体形成", "B": "根据病理表现不同分为三型", "C": "II型为免疫复合物型", "D": "基本发病机制为免疫反应", "E": "III型为抗肾小球基膜型"}, "answer": "E", "analysis": "题目问哪项不正确。急进性肾炎分三型：I型=抗GBM型；II型=免疫复合物型；III型=寡免疫/ANCA型(非抗GBM)。选项E将III型错误描述为抗GBM型(实为I型)。其余选项正确。", "keyPoint": "急进性肾炎的病理分型", "memoryTip": "I型抗GBM，II型免疫复合物，III型寡免疫/ANCA"}, {"num": 63, "type": "multi", "question": "下列哪项不是轴线翻身的目的", "options": {"A": "协助脊椎损伤的患者在床上翻身", "B": "预防压疮", "C": "预防脊椎再损伤", "D": "协助颅骨牵引的患者在床上翻身", "E": "协助昏迷病人在床上翻身"}, "answer": "E", "analysis": "题目问哪项不是轴线翻身目的。轴线翻身用于脊椎损伤/术后患者和颅骨牵引患者的翻身。昏迷患者翻身不需要轴线翻身。", "keyPoint": "轴线翻身的适应症", "memoryTip": "轴线翻身不适用于昏迷患者"}, {"num": 64, "type": "multi", "question": "引起肺血栓栓塞症的血栓几乎不来自", "options": {"A": "下腔静脉径路", "B": "上腔静脉径路", "C": "左心腔", "D": "右心腔", "E": "下肢深静脉"}, "answer": "C", "analysis": "题目问几乎不来自哪里。PTE血栓>90%来自下腔静脉(下肢深静脉)。左心腔血栓进入体循环(脑栓塞/肢体栓塞)，几乎不进入肺循环引起肺栓塞。", "keyPoint": "肺血栓栓塞症的血栓来源", "memoryTip": "左心血栓去体循环，非肺循环"}, {"num": 65, "type": "multi", "question": "系统性红斑狼疮最常发生的脏器或组织损害是", "options": {"A": "肾", "B": "肌肉、关节", "C": "皮肤", "D": "心血管", "E": "肺和胸膜"}, "answer": "A", "analysis": "SLE最常发生损害的脏器是肾脏(狼疮性肾炎)，约50~70%有临床肾损害，肾活检几乎100%有病理改变。", "keyPoint": "SLE最常累及的脏器", "memoryTip": "SLE最常累及=肾脏(狼疮性肾炎)"}, {"num": 66, "type": "multi", "question": "出现脑疝应立即", "options": {"A": "降体温", "B": "输氧", "C": "气管切开", "D": "快速静脉滴注脱水剂"}, "answer": "D", "analysis": "脑疝一旦出现应立即快速静脉滴注脱水剂(20%甘露醇)降低颅内压，这是争分夺秒的急救措施。降温、输氧、气管切开为后续措施。", "keyPoint": "脑疝的急救处理", "memoryTip": "脑疝急救=立即静滴甘露醇脱水"}, {"num": 67, "type": "multi", "question": "以下哪项不是有助于系统性红斑狼疮诊断的实验室辅助检查", "options": {"A": "血小板减少", "B": "抗核抗体阳性", "C": "抗dsDNA抗体阳性", "D": "γ球蛋白下降", "E": "补体C3下降"}, "answer": "D", "analysis": "题目问哪项不是有助于SLE诊断。SLE时gamma球蛋白应升高(多克隆B细胞活化导致)，而非下降。血小板减少、ANA阳性、抗dsDNA阳性、补体C3下降均为SLE常见异常。", "keyPoint": "SLE实验室检查特征", "memoryTip": "SLE gamma球蛋白升高非下降"}, {"num": 68, "type": "multi", "question": "PICC导管留置时间一般不超过多少个月", "options": {"A": "3", "B": "6", "C": "9", "D": "12", "E": "24"}, "answer": "D", "analysis": "PICC留置时间一般不超过12个月(1年)。CVC仅1~4周，PICC可达12个月，输液港(Port)可长期留置。", "keyPoint": "PICC导管留置时限", "memoryTip": "PICC留置不超过12个月"}, {"num": 69, "type": "multi", "question": "扩张型心肌病患者的最主要的临床表现是", "options": {"A": "呼吸道感染", "B": "室性心律失常", "C": "心力衰竭", "D": "晕厥", "E": "房室传导阻滞"}, "answer": "C", "analysis": "扩张型心肌病最主要表现为心力衰竭(进行性呼吸困难、乏力、水肿)。室性心律失常为次要表现；晕厥多见于肥厚型心肌病。", "keyPoint": "扩张型心肌病临床表现", "memoryTip": "扩张型心肌病最主要=心力衰竭"}, {"num": 70, "type": "single", "question": "低盐饮食每日烹调食盐的量", "options": {"A": "不超过2g", "B": "不超过1.5g", "C": "不少于2g", "D": "不超过3g"}, "answer": "A", "analysis": "低盐饮食每日烹调食盐不超过2g。注意与第10题区别：第10题问的是钠含量，本题问的是烹调食盐量(食盐含约40%钠)。", "keyPoint": "低盐饮食烹调食盐量", "memoryTip": "低盐饮食=烹调食盐<2g/d"}, {"num": 71, "type": "multi", "question": "全胃肠外营养支持患者可能发生的代谢性并发症有", "options": {"A": "低血糖", "B": "空气栓塞", "C": "导管败血症", "D": "肝功能异常", "E": "高渗性非酮症性昏迷"}, "answer": "AE", "analysis": "全胃肠外营养(TPN)的代谢性并发症包括：低血糖(突然停止输高糖时发生)和高渗性非酮症性昏迷(高糖输注过快)。空气栓塞和导管败血症属导管相关/感染性并发症。", "keyPoint": "TPN代谢性并发症", "memoryTip": "TPN代谢性=低血糖+高渗性非酮症昏迷"}, {"num": 72, "type": "multi", "question": "NRS-2002营养风险筛查表中属于3分项的包括", "options": {"A": "头部损伤患者", "B": "骨髓移植患者", "C": "ICU患者", "D": "腹部大手术患者", "E": "恶性肿瘤患者"}, "answer": "ABC", "analysis": "NRS-2002疾病严重程度评3分项：头部损伤、骨髓移植、ICU(APACHE>10)患者。腹部大手术和恶性肿瘤一般评2分。", "keyPoint": "NRS-2002营养风险筛查评分", "memoryTip": "NRS 3分=头部损伤+骨髓移植+ICU"}, {"num": 73, "type": "multi", "question": "腹膜的生理作用包括", "options": {"A": "润滑作用", "B": "吸收作用", "C": "渗出作用", "D": "防御作用", "E": "营养作用"}, "answer": "ABCD", "analysis": "腹膜生理功能包括：润滑作用+吸收作用+渗出作用+防御作用(含大量巨噬细胞和淋巴细胞)。营养作用不属于腹膜生理功能。", "keyPoint": "腹膜的生理功能", "memoryTip": "腹膜四功能=润滑+吸收+渗出+防御"}, {"num": 74, "type": "multi", "question": "下面哪些是上腔静脉压迫综合征的表现", "options": {"A": "头面部浮肿", "B": "呼吸困难", "C": "颈静脉怒张", "D": "上肢浮肿", "E": "口唇发绀"}, "answer": "ABCDE", "analysis": "上腔静脉压迫综合征(SVCS)全部5项均正确：头面部浮肿、呼吸困难、颈静脉怒张、上肢浮肿、口唇发绀。因上腔静脉完全受阻所致。", "keyPoint": "上腔静脉压迫综合征的表现", "memoryTip": "SVCS=5项全选(头面上肢浮肿+呼困+颈静脉+发绀)"}, {"num": 75, "type": "multi", "question": "向心性肥胖的特点是（）", "options": {"A": "黏液性水肿面容", "B": "满月脸", "C": "肢端肥大", "D": "水牛背", "E": "全身肥胖"}, "answer": "BD", "analysis": "向心性肥胖典型特征为满月脸+水牛背，因糖皮质激素过多致脂肪重新分布(面部和躯干堆积、四肢减少)。黏液性水肿面容=甲减；肢端肥大=GH过多。", "keyPoint": "向心性肥胖的特点", "memoryTip": "向心性肥胖=满月脸+水牛背"}, {"num": 76, "type": "multi", "question": "病毒性脑膜炎的临床主要表现为（）", "options": {"A": "发热", "B": "头痛", "C": "脑膜刺激征", "D": "偏瘫", "E": "眼部损伤"}, "answer": "ABC", "analysis": "病毒性脑膜炎典型三联征：发热+头痛+脑膜刺激征(颈项强直、Kernig征、Brudzinski征)。偏瘫见于脑实质病变；眼部损伤非典型。", "keyPoint": "病毒性脑膜炎的临床表现", "memoryTip": "病毒性脑膜炎=发热+头痛+脑膜刺激征"}, {"num": 77, "type": "multi", "question": "心电图检查的注意事项（）", "options": {"A": "检查前不能饱饮、饱食、吃冷饮和抽烟，需要平静休息20min。", "B": "嘱受检者在检查时确保无手机、手表等电、磁、金属物品与患者接触。", "C": "胸导联在擦拭导电膏或酒精时要注意各导分开。", "D": "请勿将左右脚串连在一起只用3个肢夹。", "E": "如正在服用洋地黄、钾盐、钙类及抗心律失常药物，应告知医生。"}, "answer": "ABCDE", "analysis": "全部5项均为正确注意事项：检查前禁饮食吸烟平静休息+去除金属物品+胸导联分格涂导电膏+不得将左右脚串联+服用相关药物应告知。", "keyPoint": "心电图检查注意事项", "memoryTip": "心电图=5项注意事项全对"}, {"num": 78, "type": "multi", "question": "脑卒中的危险因素包括（）", "options": {"A": "肥胖", "B": "颈动脉狭窄", "C": "高同型半胱氨酸血症", "D": "早期营养不良", "E": "长期被动吸烟"}, "answer": "ABCE", "analysis": "脑卒中危险因素包括肥胖、颈动脉狭窄、高同型半胱氨酸血症、长期被动吸烟。早期营养不良不是脑卒中危险因素。", "keyPoint": "脑卒中的危险因素", "memoryTip": "脑卒中危险不包括早期营养不良"}, {"num": 79, "type": "multi", "question": "下列关于短暂性脑缺血发作的叙述，正确的是（）", "options": {"A": "症状持续数分钟至数小时", "B": "无CT或MRI显示的责任病灶", "C": "简称为TIA", "D": "不会反复发作", "E": "发作后不遗留神经功能缺损症状"}, "answer": "ABCE", "analysis": "TIA正确描述：持续数分钟至数小时(不超过24h)、CT/MRI无责任病灶、简称TIA、不留后遗症。选项D不会反复发作是错误的，TIA可反复发作且是脑梗死预警信号。", "keyPoint": "TIA的临床特征", "memoryTip": "TIA可反复发作(脑梗死预警)"}, {"num": 80, "type": "multi", "question": "消化道穿孔患者必须禁食和胃肠减压的目的包括（）", "options": {"A": "减少胃内容物流入腹腔", "B": "有利于纠正酸碱平衡", "C": "改善胃壁血液循环", "D": "维持有效循环血量", "E": "促进胃肠道恢复蠕动"}, "answer": "ACE", "analysis": "穿孔禁食胃肠减压目的：减少胃内容物流入腹腔+改善胃壁血液循环+促进胃肠道蠕动恢复。纠酸和维持有效循环血量主要通过补液实现。", "keyPoint": "消化道穿孔禁食减压目的", "memoryTip": "穿孔减压=减少漏出+改善血运+促蠕动"}, {"num": 81, "type": "multi", "question": "何某，男，24岁。因双下肢水肿7天，眼睑水肿2天，伴泡沫尿就诊，诊断为肾病综合征。该病人可能发生的并发症是（）", "options": {"A": "急性肾损伤", "B": "血栓形成、栓塞", "C": "营养不良", "D": "感染", "E": "高血压脑病"}, "answer": "ABCD", "analysis": "肾病综合征常见并发症：急性肾损伤+血栓形成栓塞(高凝状态)+营养不良(蛋白质大量丢失)+感染(免疫球蛋白丢失+使用激素免疫抑制剂)。高血压脑病非典型并发症。", "keyPoint": "肾病综合征的并发症", "memoryTip": "肾病综合征并发症=感染+血栓+AKI+营养不良"}, {"num": 82, "type": "multi", "question": "使用简易呼吸囊常见的并发症有（）", "options": {"A": "急性胃扩张", "B": "窒息", "C": "气压伤", "D": "低氧血症", "E": "心律失常"}, "answer": "ABCD", "analysis": "简易呼吸囊(球囊面罩)并发症：急性胃扩张+窒息+气压伤(气胸/纵隔气肿)+低氧血症。心律失常非直接并发症。", "keyPoint": "简易呼吸囊的并发症", "memoryTip": "球囊面罩并发症=胃扩张+窒息+气压伤+低氧"}, {"num": 83, "type": "multi", "question": "以下属于肺癌非转移性的全身症状的是（）", "options": {"A": "骨关节病综合征", "B": "Cushing综合征", "C": "重症肌无力", "D": "男性乳腺增大", "E": "女性闭经"}, "answer": "ABCD", "analysis": "肺癌副癌综合征包括：骨关节病综合征+Cushing综合征(异位ACTH)+重症肌无力(Lambert-Eaton综合征)+男性乳腺增大(异位HCG)。女性闭经不属副癌综合征。", "keyPoint": "肺癌的非转移性全身症状", "memoryTip": "副癌=骨关节+Cushing+肌无力+男乳发育"}, {"num": 84, "type": "multi", "question": "付女士,55岁,因刺激性干咳5个月,视物不清10天入院,胸部X线示右上肺不规则阴影,造成了Horner综合征,表现属于Horner综合征的是（）", "options": {"A": "同侧上眼睑下垂", "B": "声音嘶哑", "C": "眼球内陷", "D": "面部无汗", "E": "瞳孔缩小"}, "answer": "ACDE", "analysis": "Horner综合征(颈交感神经麻痹)表现为同侧：上眼睑下垂+眼球内陷+面部无汗+瞳孔缩小。声音嘶哑是喉返神经受压表现，不属Horner综合征。", "keyPoint": "Horner综合征的临床表现", "memoryTip": "Horner=上睑下垂+眼球内陷+无汗+瞳孔缩小"}, {"num": 85, "type": "multi", "question": "电除颤技术常见的并发症有（）", "options": {"A": "皮肤灼伤", "B": "栓塞", "C": "心肌损伤", "D": "心律失常", "E": "肋骨骨折"}, "answer": "ABCD", "analysis": "电除颤常见并发症：皮肤灼伤+栓塞(附壁血栓脱落)+心肌损伤+心律失常。肋骨骨折是胸外按压(CPR)的并发症，非电除颤直接导致。", "keyPoint": "电除颤的并发症", "memoryTip": "电除颤=灼伤+栓塞+心肌损伤+心律失常"}]}};